<template>
    <view class="contain border_top">
        <view class="title border_bottom">
            <view class="titleLeft">
                <view class="select" @click="changeTab(1)">
                    <view class="fill" v-if="current == 1"></view>
                </view>
            </view>
            <view class="titleRight">
                お知らせ投稿機能
            </view>
        </view>
        <view class="title">
            <view class="titleLeft">
                <view class="select" @click="changeTab(2)">
                    <view class="fill" v-if="current == 2"></view>
                </view>
            </view>
            <view class="titleRight">
                Instagram連携
            </view>
        </view>
        <view class="insertContent border_bottom">
            <view class="ititle">
                埋め込み用コードをペーストしてください
            </view>
            <u-textarea placeholder="ブラウザからWeb版のInstagramにアクセスして、埋め込みコードを取得してください。" maxlength="-1" type="text" v-model="ins" ></u-textarea>
        </view>
        <view class="title">
            <view class="titleLeft">
                <view class="select"  @click="changeTab(3)">
                    <view class="fill" v-if="current == 3"></view>
                </view>
            </view>
            <view class="titleRight">
                Twitter連携
            </view>
        </view>
        <view class="insertContent border_bottom">
            <view class="ititle">
                埋め込み用コードをペーストしてください
            </view>
            <u-textarea placeholder="Twitterの埋め込みコードを取得してください。" type="text" maxlength="-1" autoHeight v-model="twitter"></u-textarea>
        </view>
        <view class="tips">
            Instagram,Twitter連携は、連携したアカウントの投稿が「お知らせ」画面に表示されます。　複数の媒体を同時に表示させることは出来ません。
        </view>
    </view>
</template>
<script>
    import {setShopInfo,getShopInfo} from "@/api/index.js"
    export default {
        data() {
            return {
                current:1,
                ins:"",
                twitter:""
            }
        },
        onLoad() {
           let that = this
           that.getShopInfo()
        },
        methods: {
            getShopInfo(){
                getShopInfo().then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        this.current = res.data.shop_info.notice_type
                        this.ins = res.data.shop_info.instagram
                        this.twitter = res.data.shop_info.twitter
                    }
                })
            },
            changeTab(e){
               this.current = e 
            },
            onNavigationBarButtonTap() {
                let that = this
                let data = {}
                data['type'] = "notice"
                data['notice_type'] = that.current
                data['instagram'] = that.ins
                data['twitter'] = that.twitter
                setShopInfo(data).then((res) => {
                    if(res.code == 200){
                        uni.showToast({
                            title:res.message
                        })
                        setTimeout(() => {
                            uni.navigateBack()
                        },1500)
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                })
            },
        }
    }
</script>

<style lang="scss">
    .insertContent{
        box-sizing: border-box;
        padding: 0 52upx 40upx;
        
        .ititle{
           font-size: 28upx;
           font-family: Hiragino Sans-W3, Hiragino Sans;
           font-weight: normal;
           color: #707070; 
           margin-bottom: 10upx;
        }
    }
    
    .tips{
       width: 646upx;
       height: 136upx;
       background: #EAEAEA;
       border-radius: 20upx;
       opacity: 1; 
       margin: 100upx auto 0;
       box-sizing: border-box;
       padding: 20upx;
       font-size: 24upx;
       font-family: Hiragino Sans-W3, Hiragino Sans;
       font-weight: normal;
       color: #1D1D1F;
    }
    
    .contain{
        box-sizing: border-box;
        padding-top: 60upx; 
    }
    .select{
        width: 40upx;
        height: 40upx;
        background: #FFFFFF;
        opacity: 1;
        border: 2upx solid #1A73E8;
        border-radius: 50%;
        box-sizing: border-box;
        padding: 6upx;
        
        .fill{
            background: #1A73E8;
            border-radius: 50%;
            height: 100%;
            width: 100%;
        }
    }
    
    .title{
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 44upx 38upx;
    }
</style>
